14	        {%- for block in messages[0]['content'] %}
15	            {%- if block['type'] == 'text' %}
16	                {{- block['text'] }}
17	            {%- elif block['type'] == 'thinking' %}
18	                {{- '[THINK]' + block['thinking'] + '[/THINK]' }}
19	            {%- else %}
20	                {{- raise_exception('Only text and thinking chunks are supported in system message contents.') }}
21	            {%- endif %}
22	        {%- endfor %}
23	    {%- endif %}
24	    {{- '[/SYSTEM_PROMPT]' -}}
25	    {%- set loop_messages = messages[1:] %}
26	{%- else %}
27	    {%- set loop_messages = messages %}
28	    {%- if default_system_message != '' %}
29	        {{- '[SYSTEM_PROMPT]' + default_system_message + '[/SYSTEM_PROMPT]' }}
30	    {%- endif %}
31	{%- endif %}
32	
33	
34	{#- Tools definition #}
35	{%- set tools_definition = '' %}
36	{%- set has_tools = false %}
37	{%- if tools is defined and tools is not none and tools|length > 0 %}
38	    {%- set has_tools = true %}
39	    {%- set tools_definition = '[AVAILABLE_TOOLS]' + (tools| tojson) + '[/AVAILABLE_TOOLS]' %}
40	    {{- tools_definition }}
41	{%- endif %}
42	
43	{#- Checks for alternating user/assistant messages. #}
44	{%- set ns = namespace(index=0) %}
45	{%- for message in loop_messages %}
46	    {%- if message.role == 'user' or (message.role == 'assistant' and (message.tool_calls is not defined or message.tool_calls is none or message.tool_calls | length == 0)) %}
47	        {%- if (message['role'] == 'user') != (ns.index % 2 == 0) %}
48	            {{- raise_exception('After the optional system message, conversation roles must alternate user and assistant roles except for tool calls and results.') }}
49	        {%- endif %}
50	        {%- set ns.index = ns.index + 1 %}
51	    {%- endif %}
52	{%- endfor %}
53	
54	{#- Handle conversation messages. #}
55	{%- for message in loop_messages %}
56	
57	    {#- User messages supports text content or text and image chunks. #}
58	    {%- if message['role'] == 'user' %}
59	        {%- if message['content'] is string %}
60	            {{- '[INST]' + message['content'] + '[/INST]' }}
61	        {%- elif message['content'] | length > 0 %}
62	            {{- '[INST]' }}
63	            {%- if message['content'] | length == 2 %}
64	                {%- set blocks = message['content'] | sort(attribute='type') %}
65	            {%- else %}
66	                {%- set blocks = message['content'] %}
67	            {%- endif %}
68	            {%- for block in blocks %}
69	                {%- if block['type'] == 'text' %}
70	                    {{- block['text'] }}
71	                {%- elif block['type'] in ['image', 'image_url'] %}
72	                    {{- '[IMG]' }}
73	                {%- else %}
74	                    {{- raise_exception('Only text, image and image_url chunks are supported in user message content.') }}
75	                {%- endif %}
76	            {%- endfor %}
77	            {{- '[/INST]' }}
78	        {%- else %}
79	            {{- raise_exception('User message must have a string or a list of chunks in content') }}
80	        {%- endif %}
81	
82	    {#- Assistant messages supports text content or text, image and thinking chunks. #}
83	    {%- elif message['role'] == 'assistant' %}
84	        {%- if (message['content'] is none or message['content'] == '' or message['content']|length == 0) and (message['tool_calls'] is not defined or message['tool_calls'] is none or message['tool_calls']|length == 0) %}
85	            {{- raise_exception('Assistant message must have a string or a list of chunks in content or a list of tool calls.') }}
86	        {%- endif %}
87	
88	        {%- if message['content'] is string and message['content'] != '' %}
89	            {{- message['content'] }}
90	        {%- elif message['content'] | length > 0 %}
91	            {%- for block in message['content'] %}
92	                {%- if block['type'] == 'text' %}
93	                    {{- block['text'] }}
94	                {%- elif block['type'] == 'thinking' %}
95	                    {{- '[THINK]' + block['thinking'] + '[/THINK]' }}
96	                {%- else %}
97	                    {{- raise_exception('Only text and thinking chunks are supported in assistant message contents.') }}
98	                {%- endif %}
99	            {%- endfor %}
100	        {%- endif %}
101	        
102	        {%- if message['tool_calls'] is defined and message['tool_calls'] is not none and message['tool_calls']|length > 0 %}
103	            {%- for tool in message['tool_calls'] %}
104	                {{- '[TOOL_CALLS]' }}
105	                {%- set name = tool['function']['name'] %}
106	                {%- set arguments = tool['function']['arguments'] %}
107	                {%- if arguments is not string %}
108	                    {%- set arguments = arguments|tojson|safe %}
109	                {%- elif arguments == '' %}
110	                    {%- set arguments = '{}' %}
111	                {%- endif %}
112	                {{- name + '[ARGS]' + arguments }}
113	            {%- endfor %}
114	        {%- endif %}
115	
116	        {{- eos_token }}
117	
118	    {#- Tool messages only supports text content. #}
119	    {%- elif message['role'] == 'tool' %}
120	        {{- '[TOOL_RESULTS]' + message['content']|string + '[/TOOL_RESULTS]' }}
121	
122	    {#- Raise exception for unsupported roles. #}
123	    {%- else %}
124	        {{- raise_exception('Only user, assistant and tool roles are supported, got ' + message['role'] + '.') }}
125	    {%- endif %}
126	{%- endfor %}
