736	common_peg_parser common_chat_peg_builder::build_json_tools_nested_keys(
737	    const ordered_json & tools,
738	    const std::string &  effective_name_key,
739	    const std::string &  effective_args_key,
740	    const std::string &  call_id_key,
741	    const std::string &  gen_call_id_key) {
742	
743	    auto tool_choices = choice();
744	
745	    auto name_spec = parse_key_spec(effective_name_key);
746	    auto args_spec = parse_key_spec(effective_args_key);
747	
748	    std::string nested_prefix     = !name_spec.first.empty() ? name_spec.first  : args_spec.first;
749	    std::string nested_name_field = !name_spec.first.empty() ? name_spec.second  : effective_name_key;
750	    std::string nested_args_field = !args_spec.first.empty() ? args_spec.second  : effective_args_key;
751	
752	    for (const auto & tool_def : tools) {
753	        if (!tool_def.contains("function")) {
754	            continue;
755	        }
756	        const auto &   function = tool_def.at("function");
757	        std::string    name     = function.at("name");
758	        ordered_json   params   = function.contains("parameters") ? function.at("parameters") : ordered_json::object();
759	
760	        auto nested_name = literal("\"" + nested_name_field + "\"") + space() + literal(":") + space() +
761	                          literal("\"") + tool_name(literal(name)) + literal("\"");
762	        auto nested_args = literal("\"" + nested_args_field + "\"") + space() + literal(":") + space() +
763	                          tool_args(schema(json(), "tool-" + name + "-schema", params));
764	
765	        auto nested_object = literal("{") + space() +
766	                            nested_name + space() + literal(",") + space() +
767	                            nested_args +
768	                            space() + literal("}");
769	
770	        // Format: { id?, "function": {...} }
771	        auto tool_parser_body = tool_open(literal("{")) + space();
772	
773	        if (!call_id_key.empty()) {
774	            auto id_spec = parse_key_spec(call_id_key);
775	            if (id_spec.first.empty()) {
776	                auto id_parser = atomic(
777	                    literal("\"" + call_id_key + "\"") + space() + literal(":") + space() +
778	                    literal("\"") + tool_id(string_content('"')) + literal("\"")
779	                );
780	                tool_parser_body = tool_parser_body + optional(id_parser + space() + literal(",") + space());
781	            }
782	        }
783	
784	        if (!gen_call_id_key.empty()) {
785	            auto gen_id_spec = parse_key_spec(gen_call_id_key);
786	            if (gen_id_spec.first.empty()) {
787	                auto gen_id_parser = atomic(
788	                    literal("\"" + gen_call_id_key + "\"") + space() + literal(":") + space() +
789	                    choice({
790	                        literal("\"") + tool_id(string_content('"')) + literal("\""),
791	                        tool_id(json_number())
792	                    })
793	                );
794	                tool_parser_body = tool_parser_body + optional(gen_id_parser + space() + literal(",") + space());
795	            }
796	        }
797	
798	        auto nested_field = literal("\"" + nested_prefix + "\"") + space() + literal(":") + space() + nested_object;
799	        tool_parser_body = tool_parser_body + nested_field + space() + tool_close(literal("}"));
800	
801	        tool_choices |= rule("tool-" + name, tool(tool_parser_body));
802	    }
803	
804	    return tool_choices;
