807	// Mode 3: Flat keys with optional ID fields and parameter ordering
808	common_peg_parser common_chat_peg_builder::build_json_tools_flat_keys(
809	    const ordered_json &             tools,
810	    const std::string &              effective_name_key,
811	    const std::string &              effective_args_key,
812	    const std::string &              call_id_key,
813	    const std::string &              gen_call_id_key,
814	    const std::vector<std::string> & parameters_order) {
815	
816	    auto tool_choices    = choice();
817	    auto name_key_parser = literal("\"" + effective_name_key + "\"");
818	    auto args_key_parser = literal("\"" + effective_args_key + "\"");
819	
820	    for (const auto & tool_def : tools) {
821	        if (!tool_def.contains("function")) {
822	            continue;
823	        }
824	        const auto &   function = tool_def.at("function");
825	        std::string    name     = function.at("name");
826	        ordered_json   params   = function.contains("parameters") ? function.at("parameters") : ordered_json::object();
827	
828	        auto tool_name_ = name_key_parser + space() + literal(":") + space() +
829	                         literal("\"") + tool_name(literal(name)) + literal("\"");
830	        auto tool_args_ = args_key_parser + space() + literal(":") + space() +
831	                         tool_args(schema(json(), "tool-" + name + "-schema", params));
832	
833	        // Build ID parsers if keys are provided
834	        common_peg_parser id_parser = eps();
835	        if (!call_id_key.empty()) {
836	            id_parser = atomic(
837	                literal("\"" + call_id_key + "\"") + space() + literal(":") + space() +
838	                choice({
839	                    literal("\"") + tool_id(string_content('"')) + literal("\""),
840	                    tool_id(json_number())
841	                })
842	            );
843	        }
844	
845	        common_peg_parser gen_id_parser = eps();
846	        if (!gen_call_id_key.empty()) {
847	            gen_id_parser = atomic(
848	                literal("\"" + gen_call_id_key + "\"") + space() + literal(":") + space() +
849	                choice({
850	                    literal("\"") + tool_id(string_content('"')) + literal("\""),
851	                    tool_id(json_number())
852	                })
853	            );
854	        }
855	
856	        // Create (parser, key) pairs for all fields, then sort by parameters_order
857	        std::vector<std::pair<common_peg_parser, std::string>> parser_pairs;
858	        parser_pairs.emplace_back(tool_name_, effective_name_key);
859	        parser_pairs.emplace_back(tool_args_, effective_args_key);
860	        if (!call_id_key.empty()) {
861	            parser_pairs.emplace_back(optional(id_parser), call_id_key);
862	        }
863	        if (!gen_call_id_key.empty()) {
864	            parser_pairs.emplace_back(optional(gen_id_parser), gen_call_id_key);
865	        }
866	
867	        std::sort(parser_pairs.begin(), parser_pairs.end(),
868	            [&parameters_order](const auto & a, const auto & b) {
869	                auto pos_a = std::find(parameters_order.begin(), parameters_order.end(), a.second);
870	                auto pos_b = std::find(parameters_order.begin(), parameters_order.end(), b.second);
871	                size_t idx_a = (pos_a == parameters_order.end()) ? parameters_order.size() : std::distance(parameters_order.begin(), pos_a);
872	                size_t idx_b = (pos_b == parameters_order.end()) ? parameters_order.size() : std::distance(parameters_order.begin(), pos_b);
873	                return idx_a < idx_b;
874	            });
875	
876	        auto ordered_body = tool_open(literal("{")) + space();
877	        for (size_t i = 0; i < parser_pairs.size(); i++) {
878	            ordered_body = ordered_body + parser_pairs[i].first;
879	            if (i < parser_pairs.size() - 1) {
880	                ordered_body = ordered_body + space() + literal(",") + space();
881	            }
882	        }
883	        ordered_body = ordered_body + space() + tool_close(literal("}"));
884	
885	        tool_choices |= rule("tool-" + name, tool(ordered_body));
886	    }
887	
888	    return tool_choices;
889	}
