1	//  Tests chat handling, including grammar generation and parsing for tool calling, for various templates.
2	//
3	//  Also acts as a CLI to generate a Markdown summary of the formats of Jinja templates,
4	//  e.g. given Minja (http://github.com/google/minja) checked out in parent dir:
5	//
6	//    cmake -B build && cmake --build build --parallel && ./build/bin/test-chat ../minja/build/tests/*.jinja 2>/dev/null
7	//
8	#include "../src/llama-grammar.h"
9	#include "../src/unicode.h"
10	#include "chat-auto-parser.h"
11	#include "chat.h"
12	#include "common.h"
13	#include "ggml.h"
14	#include "log.h"
15	
16	#include <algorithm>
17	#include <exception>
18	#include <fstream>
19	#include <functional>
20	#include <iostream>
21	#include <nlohmann/json.hpp>
22	#include <set>
23	#include <stdexcept>
24	#include <string>
25	
26	using json = nlohmann::ordered_json;
27	
28	static std::ostream & operator<<(std::ostream & os, const common_chat_msg_diff & diff) {
29	    os << "{ content_delta: " << diff.content_delta << "; ";
30	    os << "reasoning_content_delta: " << diff.reasoning_content_delta << "; ";
31	    if (diff.tool_call_index != std::string::npos) {
32	        os << "tool_call_index: " << diff.tool_call_index << "; ";
33	        os << "tool_call_delta.name: " << diff.tool_call_delta.name << "; ";
34	        os << "tool_call_delta.id: " << diff.tool_call_delta.id << "; ";
35	        os << "tool_call_delta.arguments: " << diff.tool_call_delta.arguments << "; ";
36	    }
37	    os << "}";
38	    return os;
39	}
40	
41	// operator<< for vector<common_chat_msg_diff>:
42	static std::ostream & operator<<(std::ostream & os, const std::vector<common_chat_msg_diff> & diffs) {
43	    os << "[\n";
44	    for (const auto & diff : diffs) {
45	        os << "  " << diff << ",\n";
46	    }
47	    os << "]";
48	    return os;
49	}
50	
51	static std::ostream & operator<<(std::ostream & os, const common_chat_msg & msg) {
52	    os << "{ role: " << msg.role << "; ";
53	    os << "content: " << msg.content << "; ";
54	    os << "content_parts: [\n";
55	    for (const auto & part : msg.content_parts) {
56	        os << "  { type: " << part.type << "; text: " << part.text << " },\n";
57	    }
58	    os << "]; ";
59	    os << "reasoning_content: " << msg.reasoning_content << "; ";
60	    os << "tool_calls: [\n";
61	    for (const auto & tool_call : msg.tool_calls) {
62	        os << "  { name: " << tool_call.name << "; arguments: " << tool_call.arguments << "; id: " << tool_call.id
63	           << " },\n";
64	    }
65	    os << "]";
66	    os << "}";
67	    return os;
68	}
69	
70	template <class T> static bool equals(const T & expected, const T & actual) {
71	    return expected == actual;
72	}
73	
74	static common_chat_msg normalize(const common_chat_msg & msg) {
75	    common_chat_msg normalized = msg;
76	    for (auto & tool_call : normalized.tool_calls) {
77	        try {
78	            tool_call.arguments = json::parse(tool_call.arguments).dump();
79	        } catch (const std::exception &) {
80	        }

