// Mistral Instruct v0.3 format (e.g. Mistral-Large-Instruct-2407, Mistral-Nemo-Instruct-2407):
//   - User turns:      [INST] content [/INST]
//   - System messages:  prepended to first user turn
//   - Assistant turns:  content</s>
//   - Tool calls:       [TOOL_CALLS][{"name": "fn", "arguments": {...}, "id": "xxxxxxxxx"}]</s>
//   - Tool results:     [TOOL_RESULTS]{"content": ..., "call_id": "xxx"}[/TOOL_RESULTS]
//   - Available tools:  [AVAILABLE_TOOLS][...][/AVAILABLE_TOOLS] before the last user turn
static common_chat_params common_chat_params_init_mistral_instruct_v3(const common_chat_template &          tmpl,
                                                                      const autoparser::generation_params & inputs) {
    common_chat_params data;

    auto has_tools       = inputs.tools.is_array() && !inputs.tools.empty();
    auto include_grammar = true;

    data.prompt           = common_chat_template_direct_apply_impl(tmpl, inputs);
    data.format           = COMMON_CHAT_FORMAT_PEG_NATIVE;
    data.preserved_tokens = {
        "[TOOL_CALLS]",
        "[AVAILABLE_TOOLS]",
        "[/AVAILABLE_TOOLS]",
        "[TOOL_RESULTS]",
        "[/TOOL_RESULTS]",
    };

    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
        auto generation_prompt = p.prefix(inputs.generation_prompt, "[TOOL_CALLS]");

        // Response format parser
        if (inputs.json_schema.is_object() && !inputs.json_schema.empty()) {
            return generation_prompt + p.content(p.schema(p.json(), "response-format", inputs.json_schema));
        }

        // Tool call parser
        // Format: [TOOL_CALLS][{"name": "<name>", "arguments": <json>, "id": "<9-char-id>"}, ...]
        if (has_tools && inputs.tool_choice != COMMON_CHAT_TOOL_CHOICE_NONE) {
            auto tool_choice = p.choice();
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & function = tool.at("function");
                std::string  name     = function.at("name");
                const auto & schema   = function.at("parameters");

                tool_choice |= p.rule("tool-" + name,
                    p.tool(
                        p.tool_open(p.literal("{\"name\": \"") + p.tool_name(p.literal(name)) +
                                    p.literal("\", \"arguments\": ")) +
                        p.tool_args(p.schema(p.json(), "tool-" + name + "-schema", schema)) +
                        p.literal(", \"id\": \"") +
                        p.tool_id(p.chars("[a-zA-Z0-9]", 9, 9)) +
                        p.tool_close(p.literal("\"}")))
                );
            });

            auto min_calls  = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED ? 1 : 0;
            auto max_calls  = inputs.parallel_tool_calls ? -1 : 1;
            auto tool_calls = p.trigger_rule("tool-call",
                p.literal("[TOOL_CALLS][") +
                    p.repeat(p.optional(p.literal(", ")) + tool_choice, min_calls, max_calls) +
                    p.literal("]"));

            return generation_prompt + (p.content(p.until("[TOOL_CALLS]")) << tool_calls);
        }

        // Content only parser
        include_grammar = false;
        return generation_prompt + p.content(p.rest());
    });

    data.parser = parser.save();

    if (include_grammar) {
        data.grammar_lazy = has_tools && inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;

        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
            foreach_function(inputs.tools, [&](const json & tool) {
                const auto & function = tool.at("function");
                auto         schema   = function.at("parameters");
                builder.resolve_refs(schema);
            });
            parser.build_grammar(builder, data.grammar_lazy);
        });

        data.grammar_triggers = {
            { COMMON_GRAMMAR_TRIGGER_TYPE_WORD, "[TOOL_CALLS]" }
        };
    }

    return data;
}

